import java.io.*;
import java.net.*;

public class java_52374_SocketServer_A01 {
   public static void main(String[] args) throws IOException{
       ServerSocket server = new ServerSocket(5001); // creating a socket and binding to port no (port number should be above 1024). In this case it's assigned with the default value of Port : 80 for HTTP protocol. The client will connect using same or different one
        System.out.println("Waiting For Client Connection... ");   // wait until a connection is established from any source to 'server'. It keeps waiting till connected and once its detected, it accepts that request (connection) in the server side  if there are multiple clients trying connections at port no:5001
        Socket socket = null;//initialize clientSocket as a new instance of this class by calling the binded host name. In above example "localhost" is used which represent to localhost machine on your computer only so we're initializing it here and then accepting that connection request from any source if there are multiple clients trying connections at port no:5001
        
        socket = server.accept();//Accept the incoming client communication, returns a new instance of Socket class by binding to host “localhost” on my machine using bind() method which accepts an array of network interfaces and listen for connection requests from them..   It will wait till there is any activity in its listening state until it gets connected.
        System.out.println("Connected To Client"); //If a client has attempted to connect, this line would be printed out on the console screen using standard output stream of socket class  so that one can confirm if connection establishment was successful or not when they run our program and test from there with different clients connected
        
        BufferedReader reader = new BufferedReader(new InputStreamReader (socket.getInputStream())); // create inputstream to read data sent by client, wraps around the socket stream – in other words it’ll get whatever is written into that connection on my side and print out those details from there so far
         PrintWriter writer = new PrintWriter((socket.getOutputStream()), true);//create outputStream which will write this message to server (to send data back) , wraps around the socket stream – in other words it’ll get whatever is written into that connection on my side and print out those details from there so far
        String clientMessage; //read a line of text, using inputstreamReader. readline() blocks until at least one byte available but not block if no bytes are present yet when the server receives some data..  after reading all messages we want to send back any message then it should be done by writer object which is created and true
        //send a line of text from client side - use socket’s outputStreamWriter. write() blocks until there're enough space in buffer or connection closed because no room left, but won;t block if data not available on the stream (no bytes are present yet when server receives some dat)  so we can keep writing messages and reading them back
         //Read from client end of socket inputStream. ReadLine() blocks until at least one byte is readable in this case no new line will be added after each write operation due to a lack space left on the send buffer or connection was closed because there's nothing more that can sent data  so we should keep reading back
         //print message received from client side. and print out response for it by writer object which is created in server end of socket inputStream.. after getting all messages, if you want to stop sending anything just set a line with '\n', because when the string ends (it would be recognized as empty) then connection closed
         //until 'clientMessage' variable not contain any new data from client side it will keep listening on this until some message received by server  and after that, if you want to stop sending anything just set a line with '\n', because when the string ends (it would be recognized as empty) then connection closed
        reader.close(); // close BufferedReader in both ways - read from or write outgoing messages will fail on this point due buffering is not complete until we reach end of stream before reading all content, and also after writing any message if there's nothing left to send back by the client side  socket connection closed here.
        writer.close();// close PrintWriter in both ways - write from or read outgoing messages will fail on this point due buffering is not complete until we reach end of stream before reading all content, and also after writing any message if there's nothing left to send back by the client side  socket connection closed here
        server.close();// close ServerSocket in both ways - once everything written outgoing messages will fail on this point due buffering is not complete until we reach end of stream before reading all content, and also after writing any message if there's nothing left to send back by the client side  socket connection closed here
   }
}